import React, { useState, useEffect, useCallback, useRef } from "react";
import { useParams, useLocation, useNavigate } from "react-router-dom";
import api from "../utils/api";
import { formatTime } from "../utils/algorithms";
import { useAuth } from "../context/AuthContext";

const QUESTION_COUNT = 10;

export default function QuizPage() {
  const { topicId }   = useParams();
  const { state }     = useLocation();
  const navigate      = useNavigate();
  const { updateScore } = useAuth();

  const [phase,      setPhase]      = useState("loading");
  const [questions,  setQuestions]  = useState([]);
  const [topic,      setTopic]      = useState(state?.topic || null);
  const [current,    setCurrent]    = useState(0);
  const [selected,   setSelected]   = useState(null);
  const [revealed,   setRevealed]   = useState(false);
  const [timeLeft,   setTimeLeft]   = useState(30);
  const [answers,    setAnswers]    = useState([]);
  const [sortByDiff, setSortByDiff] = useState(false);
  const [error,      setError]      = useState("");

  const timerRef     = useRef(null);
  const startTimeRef = useRef(Date.now());

  // ─────────────────────────────────────────
  // Fetch quiz
  // ─────────────────────────────────────────
  const startQuiz = useCallback(async () => {
    setPhase("loading");
    setError("");
    setAnswers([]);
    setCurrent(0);

    try {
      const { data } = await api.post("/quiz/start", {
        topicId,
        count: QUESTION_COUNT,
        sortByDifficulty: sortByDiff,
      });

      setQuestions(data.questions);
      setTopic(data.topic);
      setPhase("ready");
    } catch (err) {
      setError(err.response?.data?.error || "Failed to load quiz.");
      setPhase("error");
    }
  }, [topicId, sortByDiff]);

  useEffect(() => { startQuiz(); }, [startQuiz]);

  // ─────────────────────────────────────────
  // Timer
  // ─────────────────────────────────────────
  useEffect(() => {
    if (phase !== "question" || revealed) return;

    const limit = questions[current]?.timeLimitSeconds || 30;
    setTimeLeft(limit);

    timerRef.current = setInterval(() => {
      setTimeLeft((t) => {
        if (t <= 1) {
          clearInterval(timerRef.current);
          handleTimeout();
          return 0;
        }
        return t - 1;
      });
    }, 1000);

    return () => clearInterval(timerRef.current);
  }, [phase, current, revealed]);

  const handleTimeout = () => {
    if (revealed) return;
    clearInterval(timerRef.current);

    setRevealed(true);
    setSelected(-1);

    setAnswers((prev) => [
      ...prev,
      {
        questionId: questions[current]._id,
        selectedOption: -1,
        timedOut: true,
        timeTakenSeconds: questions[current]?.timeLimitSeconds || 30,
      },
    ]);
  };

  // ─────────────────────────────────────────
  // SELECT ANSWER (FIXED)
  // ─────────────────────────────────────────
  const handleSelect = (optIndex) => {
    if (revealed) return;
    clearInterval(timerRef.current);

    const q = questions[current];
    const timeTaken = (q.timeLimitSeconds || 30) - timeLeft;

    setSelected(optIndex);
    setRevealed(true);

    setAnswers((prev) => [
      ...prev,
      {
        questionId: q._id,
        selectedOption: optIndex,
        timedOut: false,
        timeTakenSeconds: timeTaken,
      },
    ]);
  };

  const handleNext = () => {
    setSelected(null);
    setRevealed(false);

    if (current + 1 >= questions.length) {
      submitQuiz();
    } else {
      setCurrent((c) => c + 1);
    }
  };

  // ─────────────────────────────────────────
  // SUBMIT QUIZ
  // ─────────────────────────────────────────
  const submitQuiz = async () => {
    setPhase("submitting");

    try {
      const totalTime = Math.round((Date.now() - startTimeRef.current) / 1000);

      const { data } = await api.post("/quiz/submit", {
        topicId,
        answers,
        timeTakenSeconds: totalTime,
      });

      updateScore(data.newTotalScore);
      navigate("/results", { state: { result: data, topic, questions } });
    } catch (err) {
      setError("Failed to submit quiz.");
      setPhase("question");
    }
  };

  // ─────────────────────────────────────────
  // UI STATES
  // ─────────────────────────────────────────
  if (phase === "loading" || phase === "submitting") {
    return <div style={{ textAlign: "center", padding: "4rem" }}>Loading…</div>;
  }

  if (phase === "error") {
    return (
      <div style={{ textAlign: "center", padding: "4rem" }}>
        <h2>Error</h2>
        <p>{error}</p>
        <button onClick={startQuiz}>Retry</button>
      </div>
    );
  }

  if (phase === "ready") {
    return (
      <div style={{ textAlign: "center", padding: "3rem" }}>
        <h2>{topic?.name}</h2>
        <button onClick={() => {
          startTimeRef.current = Date.now();
          setPhase("question");
        }}>
          Start Quiz
        </button>
      </div>
    );
  }

  // ─────────────────────────────────────────
  // QUESTION VIEW
  // ─────────────────────────────────────────
  const q = questions[current];
  const progress = (current / questions.length) * 100;

  return (
    <div style={{ maxWidth: 700, margin: "auto" }}>
      <h3>Question {current + 1}</h3>
      <div>{Math.round(progress)}%</div>

      <h2>{q.text}</h2>

      {/* OPTIONS */}
      {q.options.map((opt, i) => {
        const isSelected = selected === i;

        return (
          <button
            key={i}
            onClick={() => handleSelect(i)}
            disabled={revealed}
            style={{
              display: "block",
              margin: "10px 0",
              padding: "10px",
              width: "100%",
              background: isSelected ? "#ddd" : "#fff",
              border: "1px solid #ccc",
              cursor: revealed ? "default" : "pointer"
            }}
          >
            {opt}
          </button>
        );
      })}

      {/* NEXT BUTTON */}
      {revealed && (
        <button onClick={handleNext}>
          {current + 1 >= questions.length ? "Submit" : "Next"}
        </button>
      )}
    </div>
  );
}
